const expertId = $items("Webhook")[0].json.query.expert_Id;


if (!expertId) {
  throw new Error("No llegó expert_Id en query. Revisa la URL ?expert_Id=...");
}

let results = [];

for (const item of items) {
  if (!item.binary) continue;

  for (const key of Object.keys(item.binary)) {
    const b = item.binary[key];

    // ✅ Solo PDFs
    const mime = (b?.mimeType || "").toLowerCase();
    const ext = (b?.fileExtension || "").toLowerCase();
    if (!mime.includes("application/pdf") && ext !== "pdf") continue;

    const binaryKey = key.replace(/\s/g, "_");

    results.push({
      json: {
        fileName: binaryKey,  // para tu nodo Extract from PDF
        expertId: expertId    // ✅ aquí queda incluido
      },
      binary: {
        [binaryKey]: b
      }
    });
  }
}

return results;

const cvRaw = items[0].json.output;
const linkedinRaw = items[1].json.output;

// Mapeo de campos esperados en el esquema a los posibles nombres variables que llegan
const fieldMap = {
  nombre_completo: ["nombre_completo", "nombre completo", "full name", "nombre"],
  tipo_documento: ["tipo_identificacion", "tipo_documento", "tipo y número de documento de identidad"],
  numero_documento: ["numero_identificacion", "numero_documento", "numero de documento", "tipo y número de documento de identidad"],
  fecha_nacimiento: ["fecha_nacimiento", "fecha de nacimiento", "birth date"],
  genero: ["sexo", "genero", "gender"],
  pais_residencia: ["pais_residencia", "país de residencia", "country of residence"],
  numero_telefono: ["telefono", "numero_telefono", "número de teléfono", "phone number"],
  correo_electronico: ["correo", "correo_electronico", "correo electrónico", "email", "e-mail"],
  profesion: ["profesion", "profesión", "profession"],
  nivel_educativo: ["nivel_educativo", "nivel educativo", "education level"],
  ocupacion_actual: ["ocupacion_actual", "ocupación actual", "current occupation"],
  años_experiencia: ["años_experiencia_profesional", "años de experiencia profesional", "total years of professional experience"],
  años_ejecutivos: ["años_cargo_ejecutivo", "años_en_puestos_ejecutivos", "años en puestos ejecutivos", "years in executive roles"],
  años_gerencia: ["años_en_direccion_general", "años en dirección general", "years in general management"],
  años_como_docente: ["años_como_docente", "años como docente", "years as teacher"],
  años_como_emprendedor: ["años_como_emprendedor", "años como emprendedor", "years as entrepreneur"],
  sectores_o_industrias: ["sectores", "sectores_o_industrias", "sectores o industrias", "sectors or industries"],
  paises_de_experiencia: ["paises_experiencia", "países de experiencia", "countries of experience", "paises_de_experiencia"],
  habilidades_blandas: ["habilidades_blandas", "habilidades blandas", "soft skills"],
  senales_antifragilidad: ["senales_de_antifragilidad", "señales de antifragilidad", "antifragility signals", "senales_antifragilidad"],
  senior: ["perfil_senior", "senior", "perfil sénior", "profile senior"],
  calificacion: ["calificacion_senior", "calificacion", "calificación", "rating"]
};

// Función para normalizar un objeto según fieldMap
function normalizeFields(rawObj) {
  const norm = {};
  for (const [key, variants] of Object.entries(fieldMap)) {
    for (const variant of variants) {
      if (rawObj.hasOwnProperty(variant)) {
        norm[key] = rawObj[variant];
        break;
      }
    }
    // Si no existe, queda undefined
  }
  return norm;
}

const cv = normalizeFields(cvRaw);
const linkedin = normalizeFields(linkedinRaw);

function pickBest(field1, field2) {
  if (field1 == null) field1 = "";
  if (field2 == null) field2 = "";

  if (field1 !== null && field1 !== undefined && field1 !== '') // return field1;
  {
      if (field1.length > field2.length) {
        return field1;
      } else {
        return field2;
      }
  } else {
    return field2;
  }
}

function combineArrays(arr1, arr2) {
  if (typeof arr1 === 'string' && arr1.trim() !== '') arr1 = [arr1];
  else if (!Array.isArray(arr1)) arr1 = [];
  if (typeof arr2 === 'string' && arr2.trim() !== '') arr2 = [arr2];
  else if (!Array.isArray(arr2)) arr2 = [];

  const combined = [...arr1, ...arr2];
  const lowerUniq = [...new Set(combined.map(s => s.toString().toLowerCase()))];
  return lowerUniq.map(s => s.charAt(0).toUpperCase() + s.slice(1));
}

function pickMaxOrText(a, b) {
  const na = typeof a === 'number' ? a : 0;
  const nb = typeof b === 'number' ? b : 0;
  if (na || nb) return Math.max(na, nb);
  return pickBest(a, b);
}

const combined = {};

combined["nombre_completo"] = pickBest(cv["nombre_completo"], linkedin["nombre_completo"]);
combined["tipo_documento"] = pickBest(cv["tipo_documento"], linkedin["tipo_documento"]);
combined["numero_documento"] = pickBest(cv["numero_documento"], linkedin["numero_documento"]);
combined["fecha_nacimiento"] = pickBest(cv["fecha_nacimiento"], linkedin["fecha_nacimiento"]);
combined["genero"] = pickBest(cv["genero"], linkedin["genero"]);
combined["pais_residencia"] = pickBest(cv["pais_residencia"], linkedin["pais_residencia"]);
combined["numero_telefono"] = pickBest(cv["numero_telefono"], linkedin["numero_telefono"]);

const emails = new Set();
if (cv["correo_electronico"]) {
  if (Array.isArray(cv["correo_electronico"])) cv["correo_electronico"].forEach(e => emails.add(e));
  else emails.add(cv["correo_electronico"]);
}
if (linkedin["correo_electronico"]) {
  if (Array.isArray(linkedin["correo_electronico"])) linkedin["correo_electronico"].forEach(e => emails.add(e));
  else emails.add(linkedin["correo_electronico"]);
}
combined["correo_electronico"] = Array.from(emails);

combined["profesion"] = combineArrays(cv["profesion"], linkedin["profesion"]);
combined["nivel_educativo"] = combineArrays(cv["nivel_educativo"], linkedin["nivel_educativo"]);
combined["ocupacion_actual"] = combineArrays(cv["ocupacion_actual"], linkedin["ocupacion_actual"]);

// CORREGIDO: Usar los nombres de campos normalizados
combined["años_experiencia"] = pickMaxOrText(cv["años_experiencia"], linkedin["años_experiencia"]);
combined["años_cargos_ejecutivos"] = pickMaxOrText(cv["años_ejecutivos"], linkedin["años_ejecutivos"]);
combined["años_en_gerencia"] = pickMaxOrText(cv["años_gerencia"], linkedin["años_gerencia"]);
combined["años_como_docente"] = pickMaxOrText(cv["años_como_docente"], linkedin["años_como_docente"]);
combined["años_como_emprendedor"] = pickMaxOrText(cv["años_como_emprendedor"], linkedin["años_como_emprendedor"]);

combined["sectores_o_industrias"] = combineArrays(cv["sectores_o_industrias"], linkedin["sectores_o_industrias"]);
combined["paises_de_experiencia"] = combineArrays(cv["paises_de_experiencia"], linkedin["paises_de_experiencia"]);

combined["habilidades_blandas"] = combineArrays(cv["habilidades_blandas"], linkedin["habilidades_blandas"]);
combined["senales_antifragilidad"] = combineArrays(cv["senales_antifragilidad"], linkedin["senales_antifragilidad"]);

combined["senior"] = pickBest(cv["senior"], linkedin["senior"]);
combined["calificacion"] = pickBest(cv["calificacion"], linkedin["calificacion"]);

// Construir documentos Mongo
const userDoc = {
  nombre: combined["nombre_completo"] || '',
  tipo_identificacion: combined["tipo_documento"] || null,
  num_identificacion: combined["numero_documento"] || null,
  fecha_nacimiento: combined["fecha_nacimiento"] || null,
  genero: combined["genero"] || '',
  pais_residencia: combined["pais_residencia"] || '',
  telefono: combined["numero_telefono"] || '',
  correo_electronico: combined["correo_electronico"][0] || '',
  correos_alternativos: combined["correo_electronico"].slice(1) || [],
  fecha_creacion: $now.toFormat('yyyy-MM-dd HH:mm'),
  tipo_perfil: ["experto"]
};

const profileDoc = {
  profesion: combined["profesion"].join("; ") || null,
  nivel_educativo: combined["nivel_educativo"].join("; ") || null,
  ocupacion_actual: combined["ocupacion_actual"].join("; ") || null,
  años_experiencia: combined["años_experiencia"] || '0',
  años_gerencia: combined["años_en_gerencia"] || '0',
  años_ejecutivos: combined["años_cargos_ejecutivos"] || '0',
  años_docencia: combined["años_como_docente"] || '0',
  años_emprendedor: combined["años_como_emprendedor"] || '0',
  sectores: combined["sectores_o_industrias"] || [],
  paises_experiencia: combined["paises_de_experiencia"] || [],
  habilidades_blandas: combined["habilidades_blandas"] || [],
  senales_antifragilidad: combined["senales_antifragilidad"] || [],
  perfil_senior: combined["senior"] ? "Sí" : "No",
  calificacion_senior: combined["calificacion"] || '0',
  resumen_antifragil: null, // lo llenará luego el AI Agent
  habilidades_identificadas: null, // lo llenará luego el AI Agent
  dimension_principal: null // lo llenará luego el AI Agent
};

return [
  {
    json: {
      user: userDoc,
      profile: profileDoc
    }
  }
];

