// ---------- utilidades ----------
function rmDiacritics(s=""){ return s.normalize("NFD").replace(/\p{Diacritic}/gu,""); }
function normSpaces(s=""){ return s.replace(/\s+/g," ").trim(); }
function asArray(v){ if(!v) return []; return Array.isArray(v) ? v.filter(Boolean) : [String(v)]; }

function normDate(s) {
  if (!s) return "";
  const str = String(s).toLowerCase().trim();
  if (["present","actualidad","presente","actual"].includes(str)) return "Present";
  const m = str.match(/(19|20)\d{2}([-/.](0[1-9]|1[0-2]))?/);
  if (!m) return "";
  return m[2] ? `${m[0].slice(0,7).replace(/[/.]/g,"-")}` : `${m[0].slice(0,4)}`;
}

function normCompanyGeneric(s=""){
  s = rmDiacritics(s.toLowerCase());
  // quitar sufijos corporativos comunes sin listas por país
  s = s.replace(/\b(s\.a\.s?\.?|sas|ltda\.?|inc\.?|llc|corp\.?|holding|group|grupo|sa de cv|s\.l\.|sl|co\.?ltd\.?|s\.a\.|sa)\b/gi, " ");
  s = s.replace(/[^\p{L}\p{N} ]/gu," ");
  return normSpaces(s);
}
function normRole(s=""){
  s = rmDiacritics(s.toLowerCase());
  s = s.replace(/[^\p{L}\p{N} ]/gu," ");
  return normSpaces(s);
}
function tokens(s){
  return new Set(normSpaces(s).split(" ").filter(t=>t && t.length>1));
}
function jaccard(a,b){
  const A = tokens(a), B = tokens(b);
  if (A.size===0 || B.size===0) return 0;
  let inter=0;
  for (const t of A) if (B.has(t)) inter++;
  return inter / (A.size + B.size - inter);
}
function ymToInt(ym){
  if (!ym) return null;
  if (ym==="Present") return 999912;
  const [yStr,mStr] = ym.split("-");
  const y = parseInt(yStr,10);
  const m = mStr ? parseInt(mStr,10) : 12;
  if (isNaN(y)) return null;
  return y*100 + (isNaN(m)?12:m);
}
function rangesOverlap(aStart,aEnd,bStart,bEnd){
  const A1=ymToInt(aStart), A2=ymToInt(aEnd||"Present");
  const B1=ymToInt(bStart), B2=ymToInt(bEnd||"Present");
  if (A1==null || B1==null) return false;
  return (Math.max(A1,B1) <= Math.min(A2,B2));
}

// ---------- recolectar ----------
let all = [];
for (const item of items){
  const src = item.json.source || ""; // ahora viene del Set: "cv" o "linkedin"
  const list = item.json.experiences || item.json.output?.experiences || [];
  for (const e of list){
    const x = { ...e };
    x._source = src;
    x.company = x.company?.trim() || "";
    x.role = x.role?.trim() || "";
    x.location = x.location?.trim() || "";
    x.start_date = normDate(x.start_date);
    x.end_date = normDate(x.end_date);
    x.employment_type = x.employment_type || "";
    x.seniority = x.seniority || "";
    x.achievements = asArray(x.achievements);
    x.description = x.description || "";

    x._nc = normCompanyGeneric(x.company);
    x._nr = normRole(x.role);
    all.push(x);
  }
}

// ---------- dedupe exacto por clave normalizada ----------
const byExact = new Map();
const exactKey = (e)=> [e._nc, e._nr, e.start_date||"", e.end_date||""].join("|");

for (const e of all){
  const k = exactKey(e);
  if (!byExact.has(k)) byExact.set(k, e);
  else {
    const existing = byExact.get(k);
    // preferimos CV si existe
    const cvFirst = existing._source==="cv" ? existing : (e._source==="cv" ? e : existing);

    // merge prefiriendo CV
    const primary = cvFirst;
    const secondary = (primary===existing) ? e : existing;

    const out = { ...primary };
    // achievements: unión (CV prevalece pero sumamos del otro)
    const setAch = new Set([ ...asArray(primary.achievements), ...asArray(secondary.achievements) ]);
    out.achievements = [...setAch];

    // completa campos vacíos con secondary
    for (const k2 of ["role","company","location","employment_type","description","seniority"]) {
      if (!out[k2] && secondary[k2]) out[k2] = secondary[k2];
    }
    if (!out.start_date && secondary.start_date) out.start_date = secondary.start_date;
    if (!out.end_date && secondary.end_date) out.end_date = secondary.end_date;

    byExact.set(k, out);
  }
}

// ---------- fuzzy merge (para nombres distintos: "teamfoods..." vs "team foods") ----------
let pool = Array.from(byExact.values());
const used = new Array(pool.length).fill(false);

// umbrales generales
const COMPANY_TH = 0.78; // ligeramente permisivo por variaciones
const ROLE_TH = 0.72;

function mergePreferCV(a,b){
  // si uno es CV, ese es el “primary”
  const primary = (a._source==="cv") ? a : (b._source==="cv" ? b : a);
  const secondary = (primary===a) ? b : a;

  const out = { ...primary };
  const setAch = new Set([ ...asArray(primary.achievements), ...asArray(secondary.achievements) ]);
  out.achievements = [...setAch];

  for (const k of ["role","company","location","employment_type","description","seniority"]) {
    if (!out[k] && secondary[k]) out[k] = secondary[k];
  }
  if (!out.start_date && secondary.start_date) out.start_date = secondary.start_date;
  if (!out.end_date && secondary.end_date) out.end_date = secondary.end_date;
  return out;
}

const fused = [];
for (let i=0;i<pool.length;i++){
  if (used[i]) continue;
  let base = pool[i];
  for (let j=i+1;j<pool.length;j++){
    if (used[j]) continue;
    const cand = pool[j];
    const cSim = jaccard(base._nc, cand._nc);
    const rSim = jaccard(base._nr, cand._nr);
    const datesOk =
      rangesOverlap(base.start_date, base.end_date, cand.start_date, cand.end_date) ||
      (base.start_date && cand.start_date && base.start_date===cand.start_date);

    if (cSim >= COMPANY_TH && rSim >= ROLE_TH && datesOk){
      base = mergePreferCV(base, cand);
      used[j] = true;
    }
  }
  used[i] = true;
  fused.push(base);
}

// ---------- ordenar y limpiar ----------
function sortKey(e){
  const s = e.start_date==="Present" ? "9999-99" : (e.start_date || "0000");
  const ed = e.end_date==="Present" ? "9999-99" : (e.end_date || "0000");
  return `${s}|${ed}`;
}
const out = fused
  .sort((a,b)=> sortKey(b).localeCompare(sortKey(a)))
  .map(({_nc,_nr,_source, ...rest}) => rest); // quitar internos

return [{
  json: {
    experiences: out,
    _diagnostics: {
      total_experiences: out.length,
      with_achievements: out.filter(e => e.achievements && e.achievements.length).length
    }
  }
}];

// Espera items tipo: [{ json: { text: "...", info: {...} } }, { json: { text: "..."} }]
// Si ya tienes cada PDF por separado, adapta el acceso.
function clean(s) {
  if (!s) return "";
  return s
    .replace(/\n{2,}/g, "\n")                // colapsar saltos
    .replace(/[ \t]+/g, " ")                 // espacios repetidos
    .replace(/(\n)[ \t]+/g, "$1")            // espacios al inicio de línea
    .replace(/[·•▪►]/g, "-")                 // bullets raros
    .replace(/[A-Z]\s(?=[A-Z]\s)/g, (m)=>m.trim()) // títulos espaciados tipo "D I R E C C I Ó N"
    .replace(/([A-Z])\s(?=[A-Z])/g, "$1")    // pegar mayúsculas separadas
    .replace(/(\w)\s{2,}(\w)/g, "$1 $2")     // espacios dobles
    .trim();
}

const out = [];
for (const item of items) {
  const raw = item.json.text || "";
  const cleaned = clean(raw);

  // heurística para marcar la fuente
  const isLinkedin = /Resume generated from profile|LinkedIn/i.test(raw);
  const source = isLinkedin ? "linkedin" : "cv";
  out.push({
    json: {
      // source: isLinkedin ? "linkedin" : "cv",
      cleanText: "source:" + source + "\n\n" + cleaned,
    }
  });
}
return out;

const profileItem = $items("Profile")[0];          // tu JSON completo

const got = $items("Get_profile")[0]?.json || null;

const exists = !!(got && got.id);   // <- boolean 100%
return [{
